import{_ as c,C as s,o as r,c as h,a3 as o,b as d,w as t,a as l,E as n,a4 as i}from"./chunks/framework.C49Ar5GK.js";const A=JSON.parse('{"title":"设计原则：Single Controller、HybridFlow 与模块化后端","description":"从设计动机理解 veRL V1 的单一控制器、Hybrid-Controller、模块化 Engine，以及控制流、样本流和权重流的边界","frontmatter":{"title":"设计原则：Single Controller、HybridFlow 与模块化后端","description":"从设计动机理解 veRL V1 的单一控制器、Hybrid-Controller、模块化 Engine，以及控制流、样本流和权重流的边界","lesson":{"stage":"04 · 源码","order":14,"time":"60–75 分钟","level":"源码入门","question":"为什么 veRL 既像一个普通 Python 训练循环，又能调度多种分布式训练与推理后端？"}},"headers":[],"relativePath":"internals/architecture.md","filePath":"internals/architecture.md","lastUpdated":null}'),b={name:"internals/architecture.md"};function p(u,e,g,E,y,P){const a=s("Mermaid");return r(),h("div",null,[e[3]||(e[3]=o('<h1 id="设计原则-single-controller、hybridflow-与模块化后端" tabindex="-1">设计原则：Single Controller、HybridFlow 与模块化后端 <a class="header-anchor" href="#设计原则-single-controller、hybridflow-与模块化后端" aria-label="Permalink to &quot;设计原则：Single Controller、HybridFlow 与模块化后端&quot;">​</a></h1><p>veRL 的核心不是“用 Ray 启动很多进程”，而是把复杂 RL 训练拆成两层：<strong>一个控制器表达全局算法，多组分布式 worker 高效执行局部重计算</strong>。再用稳定接口隔开训练、推理、权重同步和轨迹存储后端。</p><h2 id="先用人话-总导演不亲自演所有角色" tabindex="-1">先用人话：总导演不亲自演所有角色 <a class="header-anchor" href="#先用人话-总导演不亲自演所有角色" aria-label="Permalink to &quot;先用人话：总导演不亲自演所有角色&quot;">​</a></h2><ul><li>总导演只有一个：决定先 rollout、再打分、再算 advantage、最后更新谁；</li><li>每个大型场景有自己的执行班组：FSDP、Megatron、vLLM 等在内部按多 rank 协同；</li><li>导演只说“计算 log-prob”或“更新 actor”，不指挥每一次 all-reduce；</li><li>道具和剧本分开运输：trajectory 走 TransferQueue，模型权重走 checkpoint engine；</li><li>换一个执行班组，不应重写整部戏的剧情。</li></ul><p>这正是 Single Controller、HybridFlow 和模块化后端之间的关系。</p><h2 id="四条设计原则" tabindex="-1">四条设计原则 <a class="header-anchor" href="#四条设计原则" aria-label="Permalink to &quot;四条设计原则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>解决的问题</th><th>固定提交中的落点</th></tr></thead><tbody><tr><td>高层单一控制器</td><td>PPO/GRPO 是多模型、多阶段 DAG，需清楚表达条件、循环和中间数据</td><td><code>TaskRunnerV1</code> 内的 <code>PPOTrainer.fit()</code> / <code>_step_once()</code></td></tr><tr><td>内部 SPMD 执行</td><td>大模型训练不能由控制器逐 rank 微操</td><td><code>RayWorkerGroup</code> 调用 <code>TrainingWorker</code>，Engine 内部用 <code>torch.distributed</code></td></tr><tr><td>模块化后端</td><td>算法不应绑定 FSDP、Megatron、vLLM 或某种权重传输</td><td><code>EngineRegistry</code>、rollout registry、<code>CheckpointEngineRegistry</code>、TQ backend</td></tr><tr><td>分离控制流、样本流和权重流</td><td>避免大对象全部经过 controller/Ray RPC，明确性能与故障边界</td><td>Ray RPC、TransferQueue、CheckpointEngine 分别承担三种流</td></tr></tbody></table><h2 id="single-controller-到底-单-在哪里" tabindex="-1">Single Controller：到底“单”在哪里 <a class="header-anchor" href="#single-controller-到底-单-在哪里" aria-label="Permalink to &quot;Single Controller：到底“单”在哪里&quot;">​</a></h2><p>官方的 <a href="https://verl.readthedocs.io/en/latest/single_controller.html" target="_blank" rel="noreferrer"><code>verl.single_controller</code> 设计说明</a> 给出的动机是：传统纯 SPMD 写法不容易表达 PPO 的多个计算 DAG，也不容易在 Python 控制流中检查中间 batch。veRL 因此保留一个接近单进程脚本的全局训练循环，再把粗粒度计算分发出去。</p><p>绑定提交中的真实对象关系是：</p>',10)),(r(),d(i,null,{default:t(()=>[n(a,{id:"mermaid-112",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20D%5BCLI%20Python%20%E8%BF%9B%E7%A8%8B%3Cbr%2F%3ERay%20job%20driver%5D%20--%3E%7Cray.init%7C%20R%5BTaskRunnerV1%3Cbr%2F%3E%E4%B8%80%E4%B8%AA%20Ray%20actor%5D%0A%20%20%20%20R%20--%3E%20T%5BPPOTrainer%3Cbr%2F%3Eactor%20%E5%86%85%E6%99%AE%E9%80%9A%20Python%20%E5%AF%B9%E8%B1%A1%5D%0A%20%20%20%20T%20--%3E%7C%E7%B2%97%E7%B2%92%E5%BA%A6%20API%7C%20W1%5BActor%2FRef%20WorkerGroup%5D%0A%20%20%20%20T%20--%3E%7C%E7%B2%97%E7%B2%92%E5%BA%A6%20API%7C%20W2%5BCritic%20WorkerGroup%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20T%20--%3E%20A%5BAgentLoop%20%2F%20RewardLoop%20managers%5D%0A%20%20%20%20T%20--%3E%20L%5BLLM%20server%20replicas%5D%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<p>所以 Single Controller 不等于：</p><ul><li>整个系统只有一个进程；</li><li>所有模型都放在一张 GPU；</li><li>controller 亲自执行前向、反向或 collective；</li><li>所有数据都经过 Ray object store。</li></ul><p>它表示<strong>全局 RL 数据流只有一个逻辑编排者</strong>。在 V1 中，这个编排者是运行在 <code>TaskRunnerV1</code> Ray actor 内的 <code>PPOTrainer</code>；入口见 <a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/main_ppo.py" target="_blank" rel="noreferrer"><code>main_ppo.py</code></a>，step 编排见 <a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/v1/trainer_base.py" target="_blank" rel="noreferrer"><code>trainer_base.py</code></a>。</p><h3 id="为什么不把所有逻辑都写成-spmd" tabindex="-1">为什么不把所有逻辑都写成 SPMD <a class="header-anchor" href="#为什么不把所有逻辑都写成-spmd" aria-label="Permalink to &quot;为什么不把所有逻辑都写成 SPMD&quot;">​</a></h3><p>PPO/GRPO 不只有一段“所有 rank 同时跑同一函数”的程序。rollout、reward、reference、critic 和 actor 可能拥有不同资源、并行策略、调用次数和启动条件；异步模式还要处理 staleness 与反压。高层 Python 控制流更适合描述这些变化。</p><h3 id="为什么控制器又不会成为逐算子瓶颈" tabindex="-1">为什么控制器又不会成为逐算子瓶颈 <a class="header-anchor" href="#为什么控制器又不会成为逐算子瓶颈" aria-label="Permalink to &quot;为什么控制器又不会成为逐算子瓶颈&quot;">​</a></h3><p>controller 发的是 <code>compute_log_prob</code>、<code>compute_values</code>、<code>update_actor</code> 这类粗粒度命令。一个命令进入 WorkerGroup 后，才由各 rank 的 model engine 执行大量 GPU 计算和 collective。控制器不对每个 layer 发 RPC。</p><h2 id="hybridflow-两种编程模型接在一起" tabindex="-1">HybridFlow：两种编程模型接在一起 <a class="header-anchor" href="#hybridflow-两种编程模型接在一起" aria-label="Permalink to &quot;HybridFlow：两种编程模型接在一起&quot;">​</a></h2><p><a href="https://arxiv.org/abs/2409.19256" target="_blank" rel="noreferrer">HybridFlow 论文</a>和<a href="https://verl.readthedocs.io/en/latest/blog/v0.7.html" target="_blank" rel="noreferrer">官方架构说明</a>把它称为 Hybrid-Controller：</p>',9)),(r(),d(i,null,{default:t(()=>[n(a,{id:"mermaid-159",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20SC%5B%E9%AB%98%E5%B1%82%20Single%20Controller%20%2F%20MPMD%3Cbr%2F%3E%E4%B8%8D%E5%90%8C%E8%A7%92%E8%89%B2%E8%BF%90%E8%A1%8C%E4%B8%8D%E5%90%8C%E7%A8%8B%E5%BA%8F%5D%0A%20%20%20%20SC%20--%3E%20G%5Brollout%5D%0A%20%20%20%20SC%20--%3E%20R%5Breward%5D%0A%20%20%20%20SC%20--%3E%20C%5Bcritic%5D%0A%20%20%20%20SC%20--%3E%20A%5Bactor%5D%0A%0A%20%20%20%20G%20--%3E%20S1%5B%E5%86%85%E9%83%A8%20SPMD%20ranks%5D%0A%20%20%20%20R%20--%3E%20S2%5B%E5%86%85%E9%83%A8%E6%9C%8D%E5%8A%A1%E6%88%96%20SPMD%20ranks%5D%0A%20%20%20%20C%20--%3E%20S3%5B%E5%86%85%E9%83%A8%20SPMD%20ranks%5D%0A%20%20%20%20A%20--%3E%20S4%5B%E5%86%85%E9%83%A8%20SPMD%20ranks%5D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[l(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=o('<ul><li><strong>高层 MPMD</strong>：actor、critic、rollout、reward 执行不同程序，controller 决定依赖关系；</li><li><strong>内部 SPMD</strong>：同一个角色的多个 rank 执行相同分布式程序，由 FSDP/Megatron/vLLM 等后端同步。</li></ul><p>灵活性来自上层，吞吐来自下层。这才是 “hybrid” 最重要的含义。</p><h2 id="三种容易混淆的-hybrid" tabindex="-1">三种容易混淆的 hybrid <a class="header-anchor" href="#三种容易混淆的-hybrid" aria-label="Permalink to &quot;三种容易混淆的 hybrid&quot;">​</a></h2><table tabindex="0"><thead><tr><th>说法</th><th>真正含义</th><th>当前 V1 里怎么看</th></tr></thead><tbody><tr><td>HybridFlow / Hybrid-Controller</td><td>高层单控制器 + 角色内部多控制器/SPMD</td><td>整个框架的编程模型</td></tr><tr><td><code>ActorRolloutRefWorker</code> hybrid worker</td><td>一个 worker API 可按 <code>role</code> 组装 actor、rollout、ref 子对象</td><td>见 <a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/workers/engine_workers.py" target="_blank" rel="noreferrer"><code>engine_workers.py</code></a></td></tr><tr><td>hybrid/colocate deployment</td><td>训练与推理在相同 GPU 资源上分时或共享放置</td><td><code>LLMServerManager</code>、sleep/wake、权重同步</td></tr></tbody></table><p>还要注意版本边界：原始论文中的 <strong>3D-HybridEngine</strong> 是训练/生成 reshard 的早期核心实现；绑定提交的 <code>ActorRolloutRefWorker</code> 已明确采用 native server mode，V1 通过 <code>LLMServerManager</code> 与 <code>CheckpointEngineManager</code> 管理推理副本和权重。学习设计思想可以读论文，追当前行为必须看固定源码。</p><h2 id="模块化后端-算法层只依赖稳定契约" tabindex="-1">模块化后端：算法层只依赖稳定契约 <a class="header-anchor" href="#模块化后端-算法层只依赖稳定契约" aria-label="Permalink to &quot;模块化后端：算法层只依赖稳定契约&quot;">​</a></h2>',6)),(r(),d(i,null,{default:t(()=>[n(a,{id:"mermaid-234",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5BPPOTrainer%20%E7%AE%97%E6%B3%95%E7%BC%96%E6%8E%92%5D%0A%20%20%20%20P%20--%3E%20TW%5BTrainingWorker%20API%5D%0A%20%20%20%20P%20--%3E%20RW%5BRollout%20API%5D%0A%20%20%20%20P%20--%3E%20CW%5BCheckpoint%20API%5D%0A%20%20%20%20P%20--%3E%20QW%5BTrajectory%20KV%20API%5D%0A%0A%20%20%20%20TW%20--%3E%20E1%5BFSDP%20%2F%20FSDP2%5D%0A%20%20%20%20TW%20--%3E%20E2%5BMegatron%20%2F%20VeOmni%5D%0A%20%20%20%20TW%20--%3E%20E3%5BTorchTitan%20%2F%20Automodel%5D%0A%20%20%20%20RW%20--%3E%20I1%5BvLLM%5D%0A%20%20%20%20RW%20--%3E%20I2%5BSGLang%5D%0A%20%20%20%20RW%20--%3E%20I3%5BTensorRT-LLM%5D%0A%20%20%20%20CW%20--%3E%20C1%5Bnaive%20%2F%20NCCL%20%2F%20NIXL%20%2F%20...%5D%0A%20%20%20%20QW%20--%3E%20Q1%5BSimpleStorage%5D%0A%20%20%20%20QW%20--%3E%20Q2%5BMooncakeStore%20experimental%5D%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[l(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=o('<table tabindex="0"><thead><tr><th>模块边界</th><th>controller 依赖的接口</th><th>后端选择位置</th></tr></thead><tbody><tr><td>训练 Model Engine</td><td>initialize、infer batch、train mini-batch、checkpoint、并行信息</td><td><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/workers/engine/base.py" target="_blank" rel="noreferrer"><code>EngineRegistry</code></a>，<code>actor.strategy</code> / <code>critic.strategy</code></td></tr><tr><td>Rollout Engine</td><td>resume、release、update weights、生成服务</td><td><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/workers/rollout/base.py" target="_blank" rel="noreferrer"><code>rollout/base.py</code></a>，<code>rollout.name</code> / <code>mode</code></td></tr><tr><td>Checkpoint Engine</td><td>actor → rollout 权重准备、发送与接收</td><td><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/checkpoint_engine/base.py" target="_blank" rel="noreferrer"><code>checkpoint_engine/base.py</code></a></td></tr><tr><td>TransferQueue</td><td>KV put/get、tag、partition、清理</td><td><code>transfer_queue.backend.storage_backend</code></td></tr></tbody></table><p>“可插拔”不表示任意组合必然兼容。换 backend 时仍要校验模型支持、并行 size、dtype、权重格式、设备、rollout feature 和 checkpoint transport；但这些差异应收敛在 engine/adapter/registry，而不是散落为 trainer 中的大量 <code>if backend</code>。</p><h2 id="三层与三条流" tabindex="-1">三层与三条流 <a class="header-anchor" href="#三层与三条流" aria-label="Permalink to &quot;三层与三条流&quot;">​</a></h2><p>从进程职责看，可以继续用控制面、计算面和数据面：</p><ul><li><strong>控制面</strong>：TaskRunner、PPOTrainer、各 manager；</li><li><strong>计算面</strong>：训练 WorkerGroup、rollout/reward/teacher servers；</li><li><strong>数据面</strong>：Dataset、TransferQueue、ReplayBuffer 元数据。</li></ul><p>从传输对象看，又要区分三条流：</p><table tabindex="0"><thead><tr><th>流</th><th>主要通道</th><th>典型内容</th></tr></thead><tbody><tr><td>控制流</td><td>Ray actor RPC / futures</td><td>“开始 rollout”“计算 log-prob”“更新参数”</td></tr><tr><td>样本流</td><td>TransferQueue + <code>KVBatchMeta</code></td><td>token、mask、reward、log-prob、advantage</td></tr><tr><td>权重流</td><td>CheckpointEngine + rollout adapter</td><td>actor 新权重与版本</td></tr></tbody></table><p>Ray 负责调度与 RPC，但 V1 不把整批 trajectory 当作普通 Ray 返回值来回搬。trainer 常传递的是带 keys/tags 的 <code>KVBatchMeta</code>，计算 worker 再从 TQ 取所需字段。</p><h2 id="三种-trainer-mode-保留同一抽象" tabindex="-1">三种 trainer mode 保留同一抽象 <a class="header-anchor" href="#三种-trainer-mode-保留同一抽象" aria-label="Permalink to &quot;三种 trainer mode 保留同一抽象&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>资源关系</th><th>参数同步</th><th>额外语义</th></tr></thead><tbody><tr><td><code>sync</code></td><td>训练与 rollout 共置</td><td>每个 step 后同步</td><td>最容易验证，先学它</td></tr><tr><td><code>colocate_async</code></td><td>共置并流水化</td><td>异步生命周期钩子控制</td><td>需理解缓存与 staleness</td></tr><tr><td><code>separate_async</code></td><td>训练与 rollout 分池</td><td><code>parameter_sync_step</code> 控制</td><td>独立扩缩容，资源与反压更复杂</td></tr></tbody></table><p>它们复用相同的核心组件契约；变化主要落在何时 wake/sleep、何时提交轨迹、何时同步权重，以及允许多旧的样本进入训练。</p><h2 id="读源码时用这四个问题" tabindex="-1">读源码时用这四个问题 <a class="header-anchor" href="#读源码时用这四个问题" aria-label="Permalink to &quot;读源码时用这四个问题&quot;">​</a></h2><p>遇到任何类或配置项，先问：</p><ol><li>它属于全局控制还是角色内部计算？</li><li>它传的是命令、trajectory，还是模型权重？</li><li>它是稳定接口，还是某个 backend 的实现？</li><li>它说的 hybrid 是编程模型、混合角色，还是资源共置？</li></ol><h2 id="通关检查" tabindex="-1">通关检查 <a class="header-anchor" href="#通关检查" aria-label="Permalink to &quot;通关检查&quot;">​</a></h2><p>不用看图，解释下面这句话：</p><blockquote><p><code>PPOTrainer</code> 在一个 Ray actor 中按普通 Python 控制流编排 PPO；<code>RayWorkerGroup</code> 把粗粒度调用扇出到多 rank；各 model/rollout engine 在内部用 SPMD 高效执行；TQ 与 checkpoint engine 分别传 trajectory 和权重。</p></blockquote><p>如果能同时说明“为什么单控制器不等于单进程”和“为什么 HybridFlow 不等于 actor/rollout 共置”，这一课才算通过。</p><p>下一步：<a href="./entry-and-init">入口与初始化</a>，再到 <a href="./workers">Ray 运行时、角色与资源编排</a>。</p>',19))])}const f=c(b,[["render",p]]);export{A as __pageData,f as default};
